AND COALESCE(AA.USE_YN, 'Y') = 'Y'
AND COALESCE(AA.DEL_YN, 'N') = 'N'
AND COALESCE(AA.DISP_YN, 'Y') = 'Y'
AND NOW()::DATE BETWEEN COALESCE(NULLIF(TRIM(AA.FROM_DATE), ''), '2000-01-01')::DATE AND COALESCE(NULLIF(TRIM(AA.TO_DATE) , ''), '3000-12-31')::DATE
AND AA.BANNER_MST_CD = #{bannerMstCd , jdbcType=VARCHAR}
AND AA.BANNER_SEQ = #{bannerSeq , jdbcType=INTEGER}

mapper.select:
/* com.erns.coching.banner.mapper.BannerAdDAO.getList */

SELECT 
	ZZ.*
FROM 
	(	
		SELECT

		FROM T_BANNER_AD AA






				ORDER BY AA.SORT_ORD ASC	


	) ZZ

	OFFSET #{offset} LIMIT #{rowSize}

/* com.erns.coching.banner.mapper.BannerAdDAO.load */
SELECT
, BM.BANNER_TYPE , BM.BANNER_MST_NAME FROM T_BANNER_AD AA JOIN T_BANNER_MST BM ON AA.BANNER_MST_CD = BM.BANNER_MST_CD
AND AA.BANNER_SEQ = #{bannerSeq , jdbcType=INTEGER}

mapper.insert:
		/* com.erns.coching.banner.mapper.BannerAdDAO.insert */


			SELECT nextval('seq_t_banner_ad')


		INSERT INTO T_BANNER_AD (
				BANNER_SEQ
			, BANNER_MST_CD
			, TITLE
			, CONTENT
			, FROM_DATE
			, TO_DATE
			, STATUS
			, SORT_ORD
			, DISP_YN
			, USE_YN
			, DEL_YN
			, REF_SEQ
			, REF_CODE
			, REF_URL
			, REMARKS
			, CLICKS						
			, RGTR
			, RGT_DTTM
			, CHNR
			, CHNG_DTTM

		) VALUES (
			  #{bannerSeq		, jdbcType=INTEGER}
			, #{bannerMstCd , jdbcType=VARCHAR}
			, #{title				, jdbcType=VARCHAR}
			, #{content			, jdbcType=VARCHAR}
			, #{fromDate		, jdbcType=VARCHAR}
			, #{toDate			, jdbcType=VARCHAR}
			, (SELECT COALESCE(MAX(S.SORT_ORD), 1) FROM T_BANNER_AD S WHERE S.BANNER_MST_CD = #{bannerMstCd , jdbcType=VARCHAR} )
			, COALESCE(#{dispYn	, jdbcType=VARCHAR}, 'Y')
			, COALESCE(#{useYn	, jdbcType=VARCHAR}, 'Y')
			, COALESCE(#{delYn	, jdbcType=VARCHAR}, 'N')
			, #{refSeq			, jdbcType=INTEGER}
			, #{refCode			, jdbcType=VARCHAR}
			, #{refUrl			, jdbcType=VARCHAR}
			, #{remarks			, jdbcType=VARCHAR}
			, COALESCE(#{clicks		, jdbcType=INTEGER}, 0)
			, #{rgtr						, jdbcType=INTEGER}
			, now() 
			, #{chnr						, jdbcType=INTEGER}
			, now()
    )

mapper.update:
/* com.erns.coching.banner.mapper.BannerAdDAO.update */

UPDATE T_BANNER_AD SET
		TITLE       				= #{title			, jdbcType=VARCHAR}
	, CONTENT        			= #{content		, jdbcType=VARCHAR}
	, FROM_DATE        		= #{fromDate	, jdbcType=VARCHAR}
	, TO_DATE          		= #{toDate		, jdbcType=VARCHAR}
	, STATUS       				= #{status		, jdbcType=VARCHAR}
	, REF_SEQ        			= #{refSeq		, jdbcType=INTEGER}
	, REF_CODE      			= #{refCode		, jdbcType=VARCHAR}
	, REF_URL     				= #{refUrl		, jdbcType=VARCHAR}
	, REMARKS							= #{refCode		, jdbcType=VARCHAR}			
	, CHNR 		 						= #{chnr, jdbcType=INTEGER}
	, CHNG_DTTM  					= now()

	AND BANNER_SEQ 			= #{bannerSeq	, jdbcType=INTEGER}

/* com.erns.coching.banner.mapper.BannerAdDAO.updateDispYn */

UPDATE T_BANNER_AD SET
		DISP_YN           = COALESCE(#{dispYn	, jdbcType=CHAR}, 'N')

	, CHNR 		 					= #{chnr	, jdbcType=INTEGER}
	, CHNG_DTTM  				= now()

	AND BANNER_MST_CD 	= #{bannerMstCd	, jdbcType=VARCHAR}
	AND BANNER_SEQ 			= #{bannerSeq		, jdbcType=INTEGER}

/* com.erns.coching.banner.mapper.BannerAdDAO.updateUseYn */

UPDATE T_BANNER_AD SET
		USE_YN            = COALESCE(#{useYn	, jdbcType=CHAR}, 'N')

	, CHNR 		 					= #{chnr	, jdbcType=INTEGER}
	, CHNG_DTTM  				= now()

	AND BANNER_MST_CD 	= #{bannerMstCd	, jdbcType=VARCHAR}
	AND BANNER_SEQ 			= #{bannerSeq		, jdbcType=INTEGER}

/* com.erns.coching.banner.mapper.BannerAdDAO.updateDelYn */

UPDATE T_BANNER_AD SET
		DEL_YN            = COALESCE(#{delYn	, jdbcType=CHAR}, 'N')

	, CHNR 		 					= #{chnr	, jdbcType=INTEGER}
	, CHNG_DTTM  				= now()

	AND BANNER_MST_CD 	= #{bannerMstCd	, jdbcType=VARCHAR}
	AND BANNER_SEQ 			= #{bannerSeq		, jdbcType=INTEGER}

/* com.erns.coching.banner.mapper.BannerAdDAO.updateOrder */

UPDATE T_BANNER_AD SET
		SORT_ORD      		= #{sortOrd	, jdbcType=INTEGER}

	, CHNR 		 					= #{chnr	, jdbcType=INTEGER}
	, CHNG_DTTM  				= now()

	AND BANNER_MST_CD 	= #{bannerMstCd	, jdbcType=VARCHAR}
	AND BANNER_SEQ 			= #{bannerSeq		, jdbcType=INTEGER}

/* com.erns.coching.banner.mapper.BannerAdDAO.updateClicks */

UPDATE T_BANNER_AD SET
	CLICKS      		= CLICKS + 1

	AND BANNER_MST_CD 	= #{bannerMstCd	, jdbcType=VARCHAR}
	AND BANNER_SEQ 		= #{bannerSeq	, jdbcType=INTEGER}

mapper.delete:
/* com.erns.coching.banner.mapper.BannerAdDAO.delete */

DELETE FROM T_BANNER_AD

	AND BANNER_MST_CD 	= #{bannerMstCd	, jdbcType=VARCHAR}
	AND BANNER_SEQ 		= #{bannerSeq		, jdbcType=INTEGER}
